// ════════════════════════════════════════════════════════════════════
// RUNTIME PROMPT FETCH PATTERN — read this before building Claude workflows
// ════════════════════════════════════════════════════════════════════
//
// Every workflow that calls Claude MUST fetch its system prompt from
// the operator_prompts table at runtime instead of hardcoding it.
// This workflow (Prompt Swap) writes to that table. Claude workflows
// just read from it — no redeployment needed to change behaviour.
//
// ── Fetch pattern (add these nodes before your Claude API call) ──
//
//   Node A — HTTP Request (GET, supabaseApi credential):
//     URL: https://ipidfqwlszuhjgjygbvx.supabase.co/rest/v1/operator_prompts
//     Query params:
//       component = eq.{your_component_name}   e.g. eq.main_router
//       select    = system_prompt,version
//       limit     = 1
//
//   Node B — Set / Code node (build Claude body):
//     const promptRow = $('Node A').first().json;
//     const rows = Array.isArray(promptRow) ? promptRow : [promptRow];
//     const systemPrompt = rows[0]?.system_prompt || DEFAULT_SYSTEM_PROMPT;
//     // then pass systemPrompt into the Claude messages API body
//
// ── Component name registry ──────────────────────────────────────
//   Core workflows:   main_router · context_loader · tool_dispatcher
//                     memory_read · response_formatter · confidence_fallback
//   Subagents:        lead_gen · copywriting · offer_building · funnel_mapping
//                     content_calendar · ad_strategy · email_sequence · seo_brief
//                     competitor_research · social_planning · sales_script
//                     brand_voice · analytics · automation_build
//                     client_reporting · general_question
// ════════════════════════════════════════════════════════════════════

const body           = $input.first().json.body;
const adminToken     = (body.admin_token      || '').trim();
const component      = (body.component        || '').trim();
const newPrompt      = (body.new_system_prompt || '').trim();
const versionLabel   = (body.version_label    || '').trim();

// ── Token validation ─────────────────────────────────────────────
// Constant-time string comparison to prevent timing-based enumeration.
const expectedToken  = $vars.NOVA_OPS_ADMIN_TOKEN || '';
const tokenValid     =
  adminToken.length > 0 &&
  expectedToken.length > 0 &&
  adminToken.length === expectedToken.length &&
  adminToken === expectedToken;

// ── Field validation ─────────────────────────────────────────────
let reason = null;
if      (!tokenValid)    reason = 'invalid_admin_token';
else if (!component)     reason = 'missing_component';
else if (!newPrompt)     reason = 'missing_new_system_prompt';
else if (!versionLabel)  reason = 'missing_version_label';

const isValid = reason === null;

// ── Known-component check (soft warning, not a blocker) ──────────
const KNOWN_COMPONENTS = [
  'main_router','context_loader','tool_dispatcher','memory_read',
  'response_formatter','confidence_fallback',
  'lead_gen','copywriting','offer_building','funnel_mapping',
  'content_calendar','ad_strategy','email_sequence','seo_brief',
  'competitor_research','social_planning','sales_script','brand_voice',
  'analytics','automation_build','client_reporting','general_question'
];

return [{
  json: {
    is_valid:            isValid,
    reason,
    component,
    new_system_prompt:   newPrompt,
    version_label:       versionLabel,
    is_known_component:  KNOWN_COMPONENTS.includes(component),
    updated_at:          new Date().toISOString()
  }
}];
